INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Le Vesuvio', 'لي فيزوفيو', 4.5, 'Italian, Pizza', 'إيطالي، بيتزا', 'restaurant-le-vesuvio', false, 'Le Vesuvio offers authentic Italian dining by the waterfront at Jeddah Yacht Club & Marina. Enjoy wood fired pizzas, handmade pastas, and fresh seafood in a modern, elegant setting with stunning marina views. A perfect spot for date nights, gatherings, or a refined evening by the sea.', 'يقدّم لي فيزوفيو تجربة طعام إيطالية أصيلة على الواجهة البحرية في مرسى ونادي اليخوت بجدة. استمتعوا ببيتزا الحطب، والباستا المصنوعة يدويًا، والمأكولات البحرية الطازجة في أجواء عصرية راقية وإطلالة خلابة على المرسى. المكان المثالي لسهرة راقية، أو موعد عشاء، أو تجمع مميز بجانب البحر.', 'Jeddah', 'جدة');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('ROKA', 'روكا', 4.6, 'Japanese', 'ياباني', 'restaurant-roka', false, 'ROKA Jeddah brings modern Japanese robatayaki dining to a sleek, contemporary space at Jeddah Walk. The menu features signature grilled dishes, sushi, and bold Japanese flavors, all served in a vibrant, upscale atmosphere perfect for dinners, celebrations, or a stylish night out.', 'يقدّم ROKA جدة تجربة "روبتاياكي" يابانية عصرية في مساحة أنيقة وحديثة في ممشى جدة. تتضمن القائمة أطباقهم المشوية المميزة، والسوشي، ونكهات يابانية جريئة، جميعها تُقدَّم في أجواء راقية نابضة بالحيوية—مثالية للعشاء، والاحتفالات، أو لقضاء سهرة أنيقة.', 'Jeddah', 'جدة');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Myazu', 'ميازو', 4.5, 'Japanese, Sushi', 'ياباني، سوشي', 'restaurant-myazu', true, 'Myazu Jeddah delivers contemporary Japanese fusion dining in a chic, upscale setting. With a menu that spans fresh sushi, sashimi, robata grilled dishes and creative fusion plates, it''s a great spot for elegant dinners, special occasions, or a stylish night out.', 'ميازو يقدّم تجربة طعام يابانية عصرية في أجواء راقية وأنيقة. تشمل قائمته السوشي والساشيمي الطازج، وأطباق الروباتا المشوية، وأطباق يابانية مبتكرة، مما يجعله مكانًا مثاليًا لعشاء فاخر، أو المناسبات الخاصة، أو سهرة أنيقة.', 'Jeddah', 'جدة');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Pampas', 'بامباز', 4.9, 'Latin, Barbecue', 'لاتيني، باربيكيو', 'restaurant-pampas', false, 'Pampas offers an authentic South American dining experience with a focus on premium grilled meats and bold Argentine flavors. Set in an elegant, warm atmosphere, it''s perfect for steak lovers, celebratory dinners, or anyone looking for a refined Latin inspired night out.', 'يقدّم بامباس تجربة طعام لاتينية جنوبية أصيلة تركّز على اللحوم المشوية الفاخرة ونكهات الأرجنتين القوية. يتميز بأجواء أنيقة ودافئة، مما يجعله خيارًا مثاليًا لعشّاق الستيك، ولعشاء احتفالي، أو لأي شخص يبحث عن سهرة راقية مستوحاة من المطبخ اللاتيني.', 'Jeddah', 'جدة');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Rasoi by Vineet', 'راسوي باي فينيت', 4.9, 'Indian, Asian', 'هندي، آسيوي', 'restaurant-rasoi', true, 'Rasoi by Vineet brings modern Indian fine dining to Jeddah, led by Michelin starred chef Vineet Bhatia. The restaurant blends bold Indian flavors with contemporary presentation, offering creative curries, tandoor specialties, and elegant appetizers in a refined, luxurious setting perfect for special occasions.', 'يقدّم راسوي باي فينيت تجربة طعام هندية راقية بطابع حديث في جدة، تحت إشراف الشيف الحاصل على نجمة ميشلان فينيت باتيا. يجمع المطعم بين النكهات الهندية القوية والعرض العصري للأطباق، مع توليفة من الكاري الإبداعي، وتخصصات التندور، والمقبلات الأنيقة في أجواء فاخرة وراقية مثالية للمناسبات الخاصة.', 'Jeddah', 'جدة');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Kuuru', 'كورو', 4.5, 'Japanese', 'ياباني', 'restaurant-kuuru', false, 'Kuuru in Jeddah offers refined Japanese-fusion dining in a chic, contemporary setting. Expect artfully prepared sushi, sashimi, and fusion dishes, served in a stylish ambiance ideal for elegant dinners, relaxed nights out, or special occasions.', 'يقدّم كورو جدة تجربة طعام يابانية فاخرة بلمسة فيوجن عصرية، في أجواء أنيقة وحديثة. يتوقع الزوّار سوشي وساشيمي مُحضّر بعناية، وأطباق فيوجن مبتكرة، تُقدَّم في بيئة راقية مثالية لعشاء أنيق، أو سهرة هادئة، أو مناسبة خاصة.', 'Jeddah', 'جدة');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Shang Palace', 'قصر شانق', 4.8, 'Chinese', 'صيني', 'restaurant-shang', false, 'Shang Palace brings authentic Cantonese fine dining to Jeddah with elegant interiors, traditional flavors, and refined presentation. The menu features handcrafted dim sum, signature roasted dishes, and classic Cantonese specialties, making it a perfect spot for upscale family dinners, celebrations, or a premium Chinese dining experience.', 'يقدّم قصر شانق تجربة طعام كانتونية راقية وأصيلة في جدة، مع ديكورات أنيقة ونكهات تقليدية وتقديم متقن للأطباق. تشمل القائمة ديم سام محضّر يدويًا، وأطباقهم المشوية المميزة، وتخصصات كانتونية كلاسيكية، مما يجعله مكانًا مثاليًا لعشاء عائلي فاخر، أو الاحتفالات، أو تجربة طعام صينية راقية.', 'Jeddah', 'جدة');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Lucky Llama', 'ذا لاكي لاما', 4.5, 'Latin, Japanese', 'لاتيني، ياباني', 'restaurant-lucky', false, 'The Lucky Llama offers vibrant Nikkei cuisine, blending Peruvian flavors with Japanese techniques. Enjoy ceviche, tiradito, and creative sushi in a lively, stylish setting perfect for casual dinners, date nights, or flavorful nights out.', 'يقدّم ذا لاكي لاما مطبخ نيكّي النابض بالحياة، الذي يمزج بين النكهات البيروفية والتقنيات اليابانية. استمتع بالسيفيشه، والتيراديتو، والسوشي الإبداعي في أجواء حيوية وأنيقة مثالية لعشاء غير رسمي، أو موعد، أو سهرة مليئة بالنكهات.', 'Jeddah', 'جدة');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('MANIKO', 'مانكو', 4.7, 'Peruvian, Asian', 'بيرو، آسيوي', 'restaurant-maniko', false, 'Manko Jeddah brings bold Peruvian‑fusion flavors to a stylish, modern setting. Enjoy ceviches, grilled steaks, seafood, sushi‑inspired bites, and inventive small plates, all crafted for sharing. Perfect for casual dinners, nights out with friends, or special occasions.', 'يقدّم مانكو جدة نكهات بيروفية مبتكرة وجريئة في أجواء عصرية وأنيقة. استمتع بالسيفيشه، والستيكات المشوية، والمأكولات البحرية، وقطع السوشي، وأطباق صغيرة مبتكرة—all مصممة للمشاركة. المكان مثالي لعشاء غير رسمي، أو سهرة مع الأصدقاء، أو مناسبات خاصة.', 'Jeddah', 'جدة');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Niyyali', 'نيّالي', 4.7, 'Lebanese', 'لبناني', 'restaurant-niyyali', false, 'Niyyali blends authentic Lebanese cuisine with modern elegance at Shangri La Jeddah, offering mezze, grilled dishes, and rich Levant‑style flavors in a stylish setting by the sea. With indoor dining or a terrace overlooking the Red Sea and the Corniche Circuit, it''s ideal for cozy dinners, celebrations, or a vibrant night out.', 'يقدّم نيّالي تجربة طعام لبنانية أصيلة ممزوجة بالأناقة العصرية في شانغريلا جدة، مع مقبلات مميزة، أطباق مشوية، ونكهات شامية غنية في أجواء أنيقة على البحر. يوفّر المطعم تناول الطعام داخليًا أو على التراس المطل على البحر الأحمر وكورنيش جدة، مما يجعله مثاليًا لعشاء دافئ، أو الاحتفالات، أو سهرة حيوية.', 'Jeddah', 'جدة');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Robata', 'روباتا', 4.7, 'Japanese', 'ياباني', 'riyadh-robata', false, 'Inspired by the Ainu tradition of Robatayaki, the classic Japanese “fireside cooking,” Robata brings its simple yet refined flavors to Riyadh. Located at The Canopy with a stunning open-air terrace, Robata offers an experience that truly lives up to its name.', 'مستوحى من تقاليد الأينو في الروباتاياكي، يقدّم روباتا نكهاته البسيطة والراقية في الرياض. يقع في ذا كانوبي مع تراس مفتوح مذهل.', 'Riyadh', 'الرياض');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Les Deux Magots', 'لي دو ماغو', 4.6, 'French', 'فرنسي', 'riyadh-les-deux-magots', false, 'Les Deux Magots Via Riyadh celebrates the spirit of the original Parisian landmark with a heartfelt tribute to its rich heritage. The menu honors classic French bistro cuisine, featuring simple, seasonal dishes served from breakfast through dinner — from the iconic tarte tatin to the comforting croque monsieur.', 'يحتفي لي دو ماغو في الرياض بروح المعلم الباريسي الأصلي مع تكريم صادق لتراثه العريق. تقدّم القائمة المأكولات الفرنسية الكلاسيكية.', 'Riyadh', 'الرياض');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Myazu', 'ميازو', 4.5, 'Japanese, Sushi', 'ياباني، سوشي', 'riyadh-myazu', true, 'Myazu Riyadh delivers contemporary Japanese fusion dining in a chic, upscale setting. With a menu that spans fresh sushi, sashimi, robata grilled dishes and creative fusion plates, it’s a great spot for elegant dinners, special occasions, or a stylish night out.', 'يقدّم ميازو الرياض تجربة طعام يابانية عصرية في أجواء راقية وأنيقة مع سوشي وساشيمي طازج وأطباق فيوجن مبتكرة.', 'Riyadh', 'الرياض');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Vega Cigar Lounge', 'فيغا سيجار لاونج', 4.9, 'Lounge Bites', 'مقبلات لاونج', 'riyadh-vega-cigar', false, 'Vega Cigar Lounge offers members and their guests a curated selection of premium cigars and accessories, including rare and limited editions from renowned brands. With its refined atmosphere, luxurious design, and attentive service, the lounge delivers an exceptional and memorable experience.', 'يقدّم فيغا سيجار لاونج لأعضائه وضيوفهم مجموعة مختارة من السيجار الفاخر والإكسسوارات، بما في ذلك إصدارات نادرة ومحدودة.', 'Riyadh', 'الرياض');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Madeo', 'ماديو', 4.5, 'Italian, Pizza', 'إيطالي، بيتزا', 'riyadh-madeo', false, 'Madeo Ristorante is a fine dining destination that has been serving Italian cuisine for over 35 years. Its menu highlights Tuscan specialties, combining fresh local ingredients with premium European products to create a truly exceptional dining experience.', 'ماديو ريستورانتي وجهة طعام فاخرة تقدّم المطبخ الإيطالي منذ أكثر من 35 عامًا مع تخصصات توسكانية.', 'Riyadh', 'الرياض');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Coya', 'كويا', 4.5, 'Peruvian', 'بيروفي', 'riyadh-coya', false, 'COYA is a vibrant destination inspired by Peru, offering exceptional cuisine, creative pisco infusions, and lively cultural experiences. More than a restaurant, it’s an immersive journey into the spirit of Latin America.', 'كويا وجهة نابضة بالحياة مستوحاة من بيرو، تقدّم مأكولات استثنائية وتجارب ثقافية حية. أكثر من مطعم، إنها رحلة غامرة.', 'Riyadh', 'الرياض');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Gulnaz Khanum', 'غولناز خانم', 4.8, 'Persian', 'فارسي', 'riyadh-gulnaz', false, 'A refined Persian dining experience where authentic flavors of Persia blend seamlessly with the warmth and hospitality of Shamieh.', 'تجربة طعام فارسية راقية حيث تمتزج نكهات فارس الأصيلة مع دفء وضيافة الشاميّة.', 'Riyadh', 'الرياض');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Haret Abu Issam', 'حارة أبو عصام', 4.5, 'Syrian, Lebanese', 'سوري، لبناني', 'riyadh-haret', false, 'A Syrian restaurant that brings the spirit of old Damascus to life. Surrounded by authentic details and embraced by genuine Damascene hospitality, Haret Abu Issam offers more than a meal — here, you experience the story.', 'مطعم سوري يُحيي روح دمشق القديمة. محاط بتفاصيل أصيلة وضيافة دمشقية حقيقية، حارة أبو عصام يقدّم أكثر من وجبة.', 'Riyadh', 'الرياض');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Signor Sassi', 'سينيور ساسي', 4.7, 'Italian', 'إيطالي', 'riyadh-signor-sassi', false, 'Signor Sassi in Riyadh brings the flavors of Italy to the city with a refined menu of classic and modern Italian dishes. Its elegant interior and welcoming atmosphere make every meal a memorable experience.', 'يقدّم سينيور ساسي في الرياض نكهات إيطاليا مع قائمة راقية من الأطباق الإيطالية الكلاسيكية والحديثة.', 'Riyadh', 'الرياض');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Alqandeel Restaurant', 'مطعم القنديل', 4.9, 'International, Middle Eastern', 'عالمي، شرق أوسطي', 'mecca-alqandeel', false, 'Enjoy contemporary design and a state-of-the-art kitchen at our all-day dining restaurant. Located on the mezzanine level with seating for 302 guests, it offers a diverse food and beverage experience, featuring buffet selections and live cooking stations.', 'استمتع بتصميم عصري ومطبخ حديث في مطعمنا المفتوح طوال اليوم. يقع في الطابق الميزانين ويتسع لـ302 ضيف، ويقدّم تجربة طعام متنوعة مع بوفيهات ومحطات طهي حية.', 'Mecca', 'مكة');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Prime Restaurant', 'مطعم برايم', 4.9, 'Healthy', 'صحي', 'mecca-prime', false, 'Indulge in unforgettable flavors and experience the pinnacle of luxury dining at Conrad Jabal Omar Makkah.', 'انغمس في نكهات لا تُنسى واستمتع بقمة الطعام الفاخر في كونراد جبل عمر مكة.', 'Mecca', 'مكة');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Sahtein Restaurant', 'مطعم صحتين', 5, 'Lebanese, Mediterranean', 'لبناني، متوسطي', 'mecca-sahtein', false, 'Sahtein Restaurant in Mecca offers a welcoming dining experience with a diverse menu that blends local favorites and international flavors. Known for its warm hospitality and relaxed atmosphere, it’s a great choice for families and visitors looking to enjoy a satisfying meal in a comfortable setting.', 'يقدّم مطعم صحتين في مكة تجربة طعام ترحيبية مع قائمة متنوعة تمزج بين المأكولات المحلية والنكهات العالمية. معروف بضيافته الدافئة وأجوائه المريحة.', 'Mecca', 'مكة');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Zafaran Restaurant', 'مطعم زعفران', 4.9, 'International, Mediterranean', 'عالمي، متوسطي', 'mecca-zafaran', false, 'At Zafran Restaurant, our all-day dining menu offers a delightful selection for every moment of the day — from fluffy pancakes and made-to-order omelets to gourmet sandwiches, fresh salads, pasta, and perfectly grilled meats. Whether you’re craving a hearty breakfast at noon or a light dinner in the afternoon, there’s something to satisfy every appetite.', 'في مطعم زعفران، تقدّم قائمتنا طوال اليوم مجموعة رائعة لكل لحظة من اليوم — من الفطائر الهشّة والأومليت المحضّر حسب الطلب إلى السندويشات الفاخرة والسلطات الطازجة والباستا واللحوم المشوية.', 'Mecca', 'مكة');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Al Shorfa', 'الشرفة', 4.3, 'International, Mediterranean', 'عالمي، متوسطي', 'mecca-alshorfa', false, 'Al Shorfa at Conrad Jabal Omar Makkah offers Oriental and international cuisine in a stunning setting overlooking the Holy Kaaba. Located on the 11th-floor terrace, it features panoramic views, freshly prepared dishes, and both à la carte and buffet options creating a truly memorable dining experience.', 'تقدّم الشرفة في كونراد جبل عمر مكة المأكولات الشرقية والعالمية في إطلالة خلابة على الكعبة المشرفة. تقع في تراس الطابق الحادي عشر مع إطلالات بانورامية.', 'Mecca', 'مكة');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Harrat', 'حرّات', 4.9, 'Middle Eastern, Arabic', 'شرق أوسطي، عربي', 'alula-harrat', true, 'From seaside flavors to Middle Eastern mezze, our menu celebrates AlUla’s heritage using seasonal ingredients from local sustainable farms. Perfect for any occasion, from relaxed lunches to lively dinners.', 'من نكهات البحر إلى المزة الشرق أوسطية، تحتفي قائمتنا بتراث العلا باستخدام مكونات موسمية من مزارع محلية مستدامة. مثالي لكل مناسبة.', 'AlUla', 'العلا');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Somewhere AlUla', 'سموير العلا', 4.7, 'Mediterranean, Middle Eastern', 'متوسطي، شرق أوسطي', 'alula-somewhere', false, 'Tucked within AlUla’s lush palms, Somewhere offers a creative Mediterranean-fusion menu designed for sharing. From signature wagyu baos to towering beetroot rice, enjoy a vibrant dining experience set against the stunning backdrop of the Al-Jadidah District.', 'يقع بين نخيل العلا الوارفة، ويقدّم قائمة فيوجن متوسطية إبداعية مصممة للمشاركة. من باو الواغيو المميز إلى أرز الشمندر، استمتع بتجربة طعام نابضة بالحيوية.', 'AlUla', 'العلا');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Tama Restaurant', 'مطعم تاما', 4, 'Middle Eastern, Arabic', 'شرق أوسطي، عربي', 'alula-tama', false, 'Experience the “here and now” at Tama, where ancient history meets contemporary cuisine. We celebrate the region’s flavors by infusing local harvests with spices from the historic Incense Route. Join us for a meal overlooking the infinity pool, perfectly framed by the dramatic landscapes of the Ashar Valley.', 'عش تجربة «هنا والآن» في تاما، حيث يلتقي التاريخ العريق بالمطبخ المعاصر. نحتفي بنكهات المنطقة من خلال دمج المحاصيل المحلية مع توابل طريق البخور التاريخي.', 'AlUla', 'العلا');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Saffron', 'زعفران', 4.7, 'Asian, Thai, Healthy', 'آسيوي، تايلندي، صحي', 'alula-saffron', false, 'Experience Banyan Tree’s signature flavors, where Thai chefs blend traditional soul with contemporary flair. From fragrant lemongrass to rich coconut milk, every dish is a curated work of art perfect for intimate celebrations.', 'استمتع بنكهات بانيان تري المميزة، حيث يمزج الطهاة التايلنديون بين الروح التقليدية واللمسة المعاصرة. كل طبق عمل فني مثالي للاحتفالات الحميمة.', 'AlUla', 'العلا');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Joontos Restaurant', 'مطعم جونتوس', 5, 'Spanish, Arabic', 'إسباني، عربي', 'alula-joontos', false, 'Located within the historic Dar Tantora, Joontos celebrates the art of local dining. Led by a Michelin-starred touch, the menu focuses on “Oasis-to-table” freshness, sourcing ingredients directly from AlUla’s sustainable farms. It’s a soulful culinary journey that honors the traditions of the Old Town while embracing modern refinement.', 'يقع في دار طنطورة التاريخية، ويحتفي جونتوس بفن الطعام المحلي. تركّز القائمة على نضارة «من الواحة إلى المائدة» مع مكونات من مزارع العلا المستدامة.', 'AlUla', 'العلا');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Le Voyage', 'لو فوياج', 4.5, 'French', 'فرنسي', 'southern-le-voyage', false, 'Le Voyage Abha is a fine-dining restaurant in Abha, blending traditional Saudi flavors with contemporary international cuisine. Set in an elegant space with attentive service, it’s perfect for intimate dinners or special occasions, offering fresh, locally sourced dishes and a memorable culinary experience.', 'لو فوياج أبها مطعم راقٍ يمزج بين النكهات السعودية التقليدية والمطبخ الدولي المعاصر في أجواء أنيقة وخدمة متميزة.', 'Southern Provence', 'المنطقة الجنوبية');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Farfalli', 'فارفالي', 4.6, 'Italian', 'إيطالي', 'southern-farfalli', false, 'Farfalli Café and Restaurant is a family-friendly Italian restaurant and café located on King Fahd Road in Alarin, Abha, Asir, Saudi Arabia. Known for its warm ambiance and authentic Italian cuisine, the restaurant has become a popular dining destination for residents and visitors seeking classic dishes and relaxed service in a comfortable setting.', 'فارفالي مقهى ومطعم إيطالي عائلي يقع على طريق الملك فهد في العرين بأبها. يشتهر بأجوائه الدافئة والمأكولات الإيطالية الأصيلة.', 'Southern Provence', 'المنطقة الجنوبية');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Jorry Elite', 'جوري إيليت', 4.5, 'International', 'عالمي', 'southern-jorry-elite', false, 'Jorry Elite delivers contemporary fusion dining in a chic, upscale setting. With a menu that spans fresh sushi, sashimi, robata grilled dishes and creative fusion plates, it’s a great spot for elegant dinners, special occasions, or a stylish night out.', 'جوري إيليت يقدم تجربة طعام فيوجن معاصرة في أجواء راقية وعصرية. قائمة متنوعة تشمل السوشي والساشيمي والأطباق المشوية المبتكرة.', 'Southern Provence', 'المنطقة الجنوبية');
INSERT INTO public.restaurants (name, arabic_name, rating, cuisine, arabic_cuisine, image_name, has_michelin, description, arabic_description, city, arabic_city) VALUES ('Ala Bali Restaurant', 'مطعم على بالي', 4.5, 'International', 'عالمي', 'southern-ala-bali', false, 'Ala Bali Restaurant offers a cozy setting ideal for family and friends, serving a variety of Lebanese and Italian dishes, drinks, and snacks. Guests can relax on the terrace overlooking Abha’s mountains or enjoy the charming indoor balconies for a comfortable, laid-back experience.', 'مطعم على بالي يوفر أجواء دافئة مثالية للعائلة والأصدقاء، مع تشكيلة من الأطباق اللبنانية والإيطالية والوجبات الخفيفة.', 'Southern Provence', 'المنطقة الجنوبية');
INSERT INTO public.activities (name, rating, category, image_name, location, description, city) VALUES ('Scuba Diving', 4.5, 'Free Diving', 'rectangle10', 'Jeddah, Saudi Arabia', 'Explore the Red Sea with a professional 5-hour diving experience from Jeddah.', 'Jeddah');
INSERT INTO public.activities (name, rating, category, image_name, location, description, city) VALUES ('Desert Safari', 4.7, '4WD Tours', 'rectangle8', 'Jeddah, Saudi Arabia', 'Experience the thrill of a Desert Safari Quad Bike Tour.', 'Jeddah');
INSERT INTO public.activities (name, rating, category, image_name, location, description, city) VALUES ('Half day Boat Trip', 4.9, 'On The Water', 'rectangle11', 'Jeddah, Saudi Arabia', 'Explore the Red Sea Coast and experience Jeddah''s local maritime life.', 'Jeddah');
INSERT INTO public.activities (name, rating, category, image_name, location, description, city) VALUES ('Full day Private Tour', 4.8, 'Private Sightseeing Tour', 'rectangle12', 'Jeddah, Saudi Arabia', 'Discover the charm of Jeddah on a private day tour with a local guide.', 'Jeddah');
INSERT INTO public.activities (name, rating, category, image_name, location, description, city) VALUES ('Historic Tour', 4.8, 'Half-Day Tour', 'rectangle7', 'Jeddah, Saudi Arabia', 'Discover Al-Balad, Jeddah''s historic UNESCO World Heritage district.', 'Jeddah');
INSERT INTO public.activities (name, rating, category, image_name, location, description, city) VALUES ('Moon Mountain Hike', 4.6, 'Car Tour', 'rectangle9', 'Jeddah, Saudi Arabia', 'Hike through the otherworldly Moon Valley.', 'Jeddah');
INSERT INTO public.activities (name, rating, category, image_name, location, description, city) VALUES ('Horse Riding', 4.5, 'Pack Animal Tour', 'rectangle13', 'Jeddah, Saudi Arabia', 'Feel the thrill of Jeddah''s landscapes on horseback!', 'Jeddah');
INSERT INTO public.activities (name, rating, category, image_name, location, description, city) VALUES ('Luxury Royal Camp', 4.9, 'Camping', 'riyadh-royal-camp', 'Riyadh, Saudi Arabia', 'A spacious and inviting desert camp for over 150 guests, perfect for family gatherings, events, and special occasions, set in the serene heart of the Red Sands.', 'Riyadh');
INSERT INTO public.activities (name, rating, category, image_name, location, description, city) VALUES ('Wrangler Safari', 4.7, '4WD Tour', 'riyadh-wrangler-safari', 'Riyadh, Saudi Arabia', 'Discover the beauty of the Red Sands on a luxury Wrangler safari, led by expert guides who navigate the dunes with skill and confidence. Feel the thrill as you journey across sweeping landscapes, taking in the golden horizons and the raw, untouched charm of the desert in comfort and style.', 'Riyadh');
INSERT INTO public.activities (name, rating, category, image_name, location, description, city) VALUES ('Camel Riding', 4.5, 'Pack Animal Tours', 'riyadh-camel-riding', 'Riyadh, Saudi Arabia', 'Experience a traditional Bedouin-style camel ride through breathtaking desert landscapes, where golden dunes stretch endlessly beneath the open sky. Let the gentle rhythm of the camel carry you across the sands as you take in the peaceful beauty and timeless spirit of the desert.', 'Riyadh');
INSERT INTO public.activities (name, rating, category, image_name, location, description, city) VALUES ('Horse Riding', 4.6, 'Pack Animal Tours', 'riyadh-horse-riding', 'Riyadh, Saudi Arabia', 'Enjoy a traditional horseback ride across the red dunes, inspired by the proud spirit of Arabian horsemanship. Feel the connection between rider and horse as you journey through sweeping desert landscapes, embracing the grace, strength, and timeless heritage that define this noble tradition.', 'Riyadh');
INSERT INTO public.activities (name, rating, category, image_name, location, description, city) VALUES ('A Spiritual Journey', 4.8, 'Tours', 'mecca-spiritual-journey', 'Mecca, Saudi Arabia', 'Experience a spiritual journey through Makkah, visiting Arafat, Muzdalifah, and Mina, including Jamarat Bridge and Al-Khaif Mosque. Conclude at Jabal al-Nour and Hira Cave, followed by the Revelation Exhibition, a journey of heritage and spirituality.', 'Mecca');
INSERT INTO public.activities (name, rating, category, image_name, location, description, city) VALUES ('Clock Tower Museum', 4.7, 'Museum', 'mecca-clock-tower', 'Mecca, Saudi Arabia', 'Experience the Makkah Clock Tower Museum, offering stunning views of the Holy Mosque. Perched 480 m above the Grand Mosque in Abraj Al-Bait, the museum takes you on an interactive journey through astronomy, timekeeping, Makkah''s history, and the Holy Mosque''s development, concluding with a panoramic balcony and telescopes overlooking the Kaaba.', 'Mecca');
INSERT INTO public.activities (name, rating, category, image_name, location, description, city) VALUES ('Life of the Prophet', 4.9, 'Tours', 'mecca-life-prophet', 'Mecca, Saudi Arabia', 'Embark on a spiritual and historical journey tracing the footsteps of the Prophet Muhammad, peace be upon him. Begin at Jabal Thawr, descend into the valley of Prophet Ibrahim, and conclude at Jabal al-Nour.', 'Mecca');
INSERT INTO public.activities (name, rating, category, image_name, location, description, city) VALUES ('Kiswah Factory Tour', 4.8, 'Tours', 'mecca-kiswah-factory', 'Mecca, Saudi Arabia', 'Explore Makkah''s rich Islamic heritage on this exclusive tour. Visit the Kiswah Factory exhibition to learn about the history and significance of the Kaaba''s sacred covering through an informative documentary. Then, visit the historic Al Hudaibiya, site of the pivotal Treaty of Hudaibiya, and discover its ruins and spiritual significance. A knowledgeable guide brings the history of these iconic locations to life.', 'Mecca');
INSERT INTO public.activities (name, rating, category, image_name, location, description, city) VALUES ('Discover Hira Tour', 4.6, 'Tours', 'mecca-hira-tour', 'Mecca, Saudi Arabia', 'Today, explore the Hira district in Makkah, beginning with the Revelation Exhibition Prophet Muhammad (SAW). Next, visit the Museum of the Holy Quran''s impact. The tour concludes with a climb to Jabal al-Nour and the blessed Cave of Hira, offering breathtaking views and deep spiritual significance, before returning to the hotel.', 'Mecca');
INSERT INTO public.activities (name, rating, category, image_name, location, description, city) VALUES ('Hegra Day Tour', 4.9, 'Tours', 'alula-hegra-tour', 'AlUla, Saudi Arabia', 'Step into the past at Saudi Arabia''s premier UNESCO site. Guided by local Rawis, you''ll discover the majestic tombs and sacred halls of the Nabataean civilization. An immersive, storytelling-led tour featuring AlUla''s most iconic landmarks, including the monumental Qasr Al-Farid.', 'AlUla');
INSERT INTO public.activities (name, rating, category, image_name, location, description, city) VALUES ('Gharameel Stargazing', 4.8, 'Nature and Outdoors', 'alula-gharameel-stargazing', 'AlUla, Saudi Arabia', 'Escape to Gharameel for a breathtaking view of the Milky Way, framed by ancient rock formations and zero light pollution. Whether you''re exploring the landscape by moonlight or tracking constellations on darker nights, the experience concludes with a traditional grilled dinner around a warm campfire.', 'AlUla');
INSERT INTO public.activities (name, rating, category, image_name, location, description, city) VALUES ('Madakhel Garden Hike', 4.7, 'Adventure', 'alula-madakhel-hike', 'AlUla, Saudi Arabia', 'Hike through the shaded trails of Shaaran Nature Reserve, a paradise of diverse wildlife and striking geology. Discover the beauty of the canyon as you trek beneath a lush green canopy framed by towering sandstone walls.', 'AlUla');
INSERT INTO public.activities (name, rating, category, image_name, location, description, city) VALUES ('Wheels Bike Hub', 4.6, 'Adventure', 'alula-wheels-bike', 'AlUla, Saudi Arabia', 'Rent a bike at Wheels Bike Hub and hit the scenic 26km path from AlAtheeb to Hegra. Whether you need a quick 30-minute ride or a 2-hour adventure, we provide rentals, road assistance, and expert servicing. Finish your journey at our Bike Hub Cafe with a fresh juice or coffee.', 'AlUla');
INSERT INTO public.activities (name, rating, category, image_name, location, description, city) VALUES ('Archaeology Tour', 4.8, 'Tour', 'alula-archaeology-tour', 'AlUla, Saudi Arabia', 'Join an expert-led journey to explore hidden sites and live excavations not yet open to the public. This premium experience features vintage Land Rover tours, professional archaeological insights, and a gourmet lunch in the Oasis.', 'AlUla');
INSERT INTO public.activities (name, rating, category, image_name, location, description, city) VALUES ('Historical Tour', 4.9, 'Tours', 'southern-historical-tour', 'Alsoudah, Saudi Arabia', 'Explore the 900-year-old Rijal Almaa Village near Abha on a small-group tour with included transportation. Enjoy a day of hiking, sightseeing, and local dining while discovering the rich heritage of Saudi Arabia.', 'Southern Provence');
INSERT INTO public.activities (name, rating, category, image_name, location, description, city) VALUES ('Trip to Hima Wells', 4.8, 'Trips', 'southern-hima-wells', 'Najran, Saudi Arabia', 'Join a day tour to explore Al-Ukhdood Archaeological City, an ancient Himyarite site with ruins and inscriptions, then visit Hima Wells, a UNESCO site famous for historic water sources and rock carvings. Guided by local experts, this tour offers an authentic and meaningful journey through southern Arabia’s history and culture.', 'Southern Provence');
INSERT INTO public.activities (name, rating, category, image_name, location, description, city) VALUES ('Coffee Plantation Tour', 4.7, 'Tours', 'southern-coffee-plantation', 'Abha, Saudi Arabia', 'Experience a local coffee plantation with farmers and discover how coffee shapes southern culture. Then enjoy an off-road adventure through the mountains to the highest peak of the Black Mountain.', 'Southern Provence');
INSERT INTO public.activities (name, rating, category, image_name, location, description, city) VALUES ('Soudah Hiking', 4.8, 'Adventures', 'southern-soudah-hiking', 'Abha, Saudi Arabia', 'Hike an optional 8 km trail at 3,000 m above sea level in Abha’s Sawda Mountains. This 250-year-old path winds to the mountain base, surrounded by lush, perennial juniper trees, a symbol of the region.', 'Southern Provence');
INSERT INTO public.activities (name, rating, category, image_name, location, description, city) VALUES ('Fatima Museum', 4.6, 'Museum', 'southern-fatima-museum', 'Abha, Saudi Arabia', 'The Fatima Museum showcases the rich cultural heritage of Saudi Arabia through a curated collection of traditional artifacts, clothing, crafts, and historical exhibits. Visitors can explore the country’s history, customs, and artistic traditions in an engaging and educational environment that celebrates Saudi heritage.', 'Southern Provence');
INSERT INTO public.season_events (name, category, image_name, location, description, city) VALUES ('Winter Wonderland', 'Seasonal Attraction', 'season-winter-wonderland', 'Jeddah, Saudi Arabia', 'Step into a magical winter experience in the heart of Jeddah. Winter Wonderland brings snow, festive lights, rides, and live entertainment for the whole family. A seasonal must-visit with food stalls, games, and unforgettable holiday vibes.', 'Jeddah');
INSERT INTO public.season_events (name, category, image_name, location, description, city) VALUES ('Balad Beast', 'Live music', 'season-balad-beast', 'Jeddah, Saudi Arabia', 'Experience the ultimate music festival in Jeddah''s historic Al-Balad district. Balad Beast features international and regional artists, electrifying performances, and an unforgettable atmosphere under the stars.', 'Jeddah');
INSERT INTO public.season_events (name, category, image_name, location, description, city) VALUES ('The Snow Dome', 'Seasonal Attraction', 'season-snow-dome', 'Jeddah, Saudi Arabia', 'Escape the heat and enjoy real snow in Jeddah! The Snow Dome offers snow tubing, ice slides, snowball fights, and a winter wonderland atmosphere perfect for families and friends.', 'Jeddah');
INSERT INTO public.season_events (name, category, image_name, location, description, city) VALUES ('Ice Rink', 'Seasonal Attraction', 'season-ice-rink', 'Jeddah, Saudi Arabia', 'Glide across the ice at Jeddah''s premier seasonal ice rink. Perfect for beginners and experienced skaters alike, with professional instructors, music, and a festive atmosphere.', 'Jeddah');
INSERT INTO public.season_events (name, category, image_name, location, description, city) VALUES ('Tropical Land', 'Adventure', 'season-tropical-land', 'Jeddah, Saudi Arabia', 'Dive into a tropical adventure with water rides, jungle-themed attractions, and exotic experiences. Tropical Land is the ultimate destination for thrill-seekers and families looking for fun.', 'Jeddah');
INSERT INTO public.season_events (name, category, image_name, location, description, city) VALUES ('Notat Watar', 'Karaoke', 'season-notat-watar', 'Jeddah, Saudi Arabia', 'Sing your heart out at Notat Watar, Jeddah''s premier karaoke and live music venue. Enjoy an evening of Arabic and international hits in a vibrant, social atmosphere.', 'Jeddah');
INSERT INTO public.season_events (name, category, image_name, location, description, city) VALUES ('Almasar', 'Seasonal Attraction', 'riyadh-almasar', 'Riyadh, Saudi Arabia', 'Celebrate Ramadan at the elegant Almasar Ramadan Tent at Sports Boulevard – Arts Tower (Almasar). A warm and refined setting for Iftar and Suhoor, perfect for families, friends, and corporate gatherings, with curated dining and bespoke menu options available upon request.', 'Riyadh');
INSERT INTO public.season_events (name, category, image_name, location, description, city) VALUES ('VUZ Dome – Immersive Cinema', 'Cinema', 'riyadh-dome-cinema', 'Riyadh, Saudi Arabia', 'VUZ Dome takes you to another world with a fully immersive 360° cinema experience. With a Premium Ticket, enjoy comfortable seating and choose from magical animations, thrilling adventures, and breathtaking documentaries. Book now and feel the thrill from every angle.', 'Riyadh');
INSERT INTO public.season_events (name, category, image_name, location, description, city) VALUES ('Layali Al-Diriyah', 'Seasonal Attraction', 'riyadh-layali-diriyah', 'Riyadh, Saudi Arabia', 'In the historic Al-Murayih district, Layali Al-Diriyah shines with global flavors and refined ambiance that blend tradition and modernity. Enjoy exclusive dining, live performances, and a vibrant celebration of Saudi hospitality in the heart of Diriyah.', 'Riyadh');
INSERT INTO public.season_events (name, category, image_name, location, description, city) VALUES ('Khemah The Groves', 'Seasonal Attraction', 'riyadh-khemah-groves', 'Riyadh, Saudi Arabia', 'From the first call to Iftar to the calm of Sahoor, Khemah The Groves Village invites you to live buffet cottages surrounded by nature and inspired by Saudi heritage. Enjoy indoor and outdoor seating with a relaxed Kashta-style Iftar, perfect for memorable Ramadan gatherings.', 'Riyadh');
INSERT INTO public.season_events (name, category, image_name, location, description, city) VALUES ('Mirkaz', 'Seasonal Attraction', 'mecca-mirkaz', 'Mecca, Saudi Arabia', 'Celebrate Ramadan at the elegant Merkaz Albalad Almeen. A warm and refined setting for Iftar and Suhoor, perfect for families, friends, and corporate gatherings, with curated dining and bespoke menu options available upon request.', 'Mecca');
INSERT INTO public.season_events (name, category, image_name, location, description, city) VALUES ('AlUla Skyrise', 'Seasonal Attraction', 'alula-skyrise', 'AlUla, Saudi Arabia', 'Join AlUla Skyrise for a breathtaking mass ballooning event featuring 30 balloons rising together. Guests enjoy door-to-door luxury transfers from select 4- and 5-star hotels and pre-flight refreshments. Once airborne, spend an hour soaking in 360-degree views of the historic landscape before a smooth return to your starting point.', 'AlUla');
INSERT INTO public.season_events (name, category, image_name, location, description, city) VALUES ('Balloon Glow Show', 'Seasonal Attraction', 'alula-balloon-glow', 'AlUla, Saudi Arabia', 'Experience a spectacular fusion of light, music, and motion at the Hot Air Balloon Glow Show. Watch as 12 balloons glow in perfect choreography, accompanied by acrobats and stunning projections. With live DJ sets and local food stalls, it''s a full-sensory evening for the whole family.', 'AlUla');
INSERT INTO public.season_events (name, category, image_name, location, description, city) VALUES ('AlUla Desert Blaze', 'Seasonal Attraction', 'alula-desert-blaze', 'AlUla, Saudi Arabia', 'Desert Blaze 2025 challenged runners to conquer AlUla''s summer terrain across four intense distances. From premium race kits to the vibrant finish line, it was a true journey of endurance. Coming back in 2026—stay updated via the Experience AlUla app and our social channels to secure your spot.', 'AlUla');
INSERT INTO public.season_events (name, category, image_name, location, description, city) VALUES ('Tethered Hot Air Balloon', 'Seasonal Attraction', 'alula-tethered-balloon', 'AlUla, Saudi Arabia', 'Take to the skies with the Tethered Hot Air Balloon Experience. Ascend 50 meters above Al Manshiyah Plaza for 20 minutes of breathtaking, 360-degree views. It''s the perfect way to witness AlUla''s unique landscape from a new perspective while staying safely moored.', 'AlUla');
INSERT INTO public.season_events (name, category, image_name, location, description, city) VALUES ('Skies Festival Concert', 'Seasonal Attraction', 'alula-skies-concert', 'AlUla, Saudi Arabia', 'Join us at Thanaya for an unforgettable evening as Arabic pop icon Nancy Ajram takes the stage under AlUla''s starlit sky. Set against a backdrop of dramatic desert landscapes, this AlUla Skies Festival performance promises a vibrant night of music, emotion, and celebration with one of the region''s most beloved stars.', 'AlUla');
INSERT INTO public.season_events (name, category, image_name, location, description, city) VALUES ('Incense Road Journey', 'Seasonal Attraction', 'alula-incense-road', 'AlUla, Saudi Arabia', 'Winner of Best Arts & Culture Event at the 2025 Saudi Events Awards, this two-hour journey brings AlUla''s mud-brick history to life. Through live performances and cutting-edge tech, you''ll uncover the secrets and living memories of the desert''s ancient communities.', 'AlUla');
INSERT INTO public.season_events (name, category, image_name, location, description, city) VALUES ('Wasal Festival', 'Seasonal Attraction', 'southern-wasal-festival', 'Abha, Saudi Arabia', 'A vibrant food festival celebrating the rich flavors of Asir heritage, featuring traditional dishes and authentic local cuisine. Held in Al-Meftaha district in Abha, the festival offers visitors a true taste of Asiri culture in a lively and welcoming atmosphere.', 'Southern Provence');
INSERT INTO public.season_events (name, category, image_name, location, description, city) VALUES ('Al-Masqi Heritage Village', 'Seasonal Attraction', 'southern-masqi-village', 'Abha, Saudi Arabia', 'A cultural destination featuring traditional folk performances, handcrafted arts, and an authentic heritage atmosphere that beautifully reflects the history and traditions of the region.', 'Southern Provence');
INSERT INTO public.cars (name, category, passengers, image_name, about) VALUES ('Chevrolet Tahoe', 'Standard', 7, 'car-tahoe', 'The Chevrolet Tahoe delivers a comfortable and reliable ride with a spacious interior and smooth performance. Ideal for families or groups.');
INSERT INTO public.cars (name, category, passengers, image_name, about) VALUES ('Ford Taurus', 'Standard', 4, 'car-taurus', 'The Ford Taurus offers a comfortable and practical ride with a spacious interior and smooth handling.');
INSERT INTO public.cars (name, category, passengers, image_name, about) VALUES ('GMC Yukon', 'Standard', 7, 'car-yukon', 'The GMC Yukon offers a powerful and comfortable ride with a spacious interior and smooth performance.');
INSERT INTO public.cars (name, category, passengers, image_name, about) VALUES ('BMW 7 Series', 'Luxury', 4, 'car-bmw7', 'BMW 7 Series offers a luxury driving experience with refined comfort and advanced technology.');
INSERT INTO public.cars (name, category, passengers, image_name, about) VALUES ('Mercedes-Benz S-Class', 'Luxury', 4, 'car-sclass', 'The Mercedes-Benz S-Class defines ultimate luxury with exceptional comfort and cutting edge technology.');
INSERT INTO public.cars (name, category, passengers, image_name, about) VALUES ('Lucid Air', 'Luxury', 4, 'car-lucid-air', 'Lucid Air delivers a modern luxury experience with a sleek design and ultra smooth performance.');
INSERT INTO public.cars (name, category, passengers, image_name, about) VALUES ('Mercedes-Benz V-Class', 'Luxury', 8, 'car-vclass', 'The Mercedes-Benz V-Class offers a spacious and comfortable ride, ideal for families and groups.');
INSERT INTO public.cars (name, category, passengers, image_name, about) VALUES ('VIP Mini Bus', 'Luxury', 15, 'car-vip-minibus', 'The VIP Mini Bus is designed for comfortable group travel with spacious seating and premium interiors.');
